// floorplan.service.ts - VERSIONE CORRETTA
import { Injectable, inject } from '@angular/core';
import { BaseService } from '../Base/base.service';
import { FloorPlan, Table, TableShape } from '../../models';

@Injectable({ providedIn: 'root' })
export class FloorPlanService extends BaseService<FloorPlan> {
  protected getTableName(): string { return 'restaurant_floor_plans'; }

  readonly tableShapes: TableShape[] = [
    { id: 'rect', name: 'Rettangolare', type: 'rectangle', default_width: 120, default_height: 80, icon: 'rectangle' },
    { id: 'circle', name: 'Rotondo', type: 'circle', default_width: 100, default_height: 100, icon: 'circle' },
    { id: 'square', name: 'Quadrato', type: 'square', default_width: 100, default_height: 100, icon: 'square' },
  ];

  // ✅ CORREZIONE: Override corretto senza parametri aggiuntivi
  override async loadData(): Promise<void> {
    try {
      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) return;

      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .select('*')
        .eq('restaurant_id', restaurantId)
        .order('created_at', { ascending: false });

      if (error) throw error;
      this.dataSubject.next(data || []);
    } catch (error: any) {
      console.error(`Error loading ${this.getTableName()}:`, error);
      this.errorSubject.next(error.message);
      this.dataSubject.next([]);
    }
  }

  async updateFloorPlan(id: string, updates: Partial<FloorPlan>): Promise<boolean> {
    try {
      const updateData = {
        ...updates,
        updated_at: new Date().toISOString()
      };

      const { error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .update(updateData)
        .eq('id', id);

      if (error) throw error;

      await this.loadData();
      return true;
    } catch (error) {
      console.error('❌ Error updating floor plan:', error);
      return false;
    }
  }

  async loadFloorPlans(): Promise<void> {
    return this.loadData();
  }

  getTableShapes(): TableShape[] { return this.tableShapes; }

  getTableShapeById(id: string): TableShape | undefined {
    return this.tableShapes.find(shape => shape.id === id);
  }

  // ✅ MANTIENI I METODI SPECIFICI CHE AVEVI PRIMA
  async createFloorPlan(floorPlan: Omit<FloorPlan, 'id' | 'created_at' | 'updated_at'>): Promise<FloorPlan | null> {
    try {
      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) return null;

      const floorPlanToInsert = {
        ...floorPlan,
        restaurant_id: restaurantId,
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString()
      };

      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .insert(floorPlanToInsert)
        .select()
        .single();

      if (error) throw error;

      await this.loadData();
      return data;
    } catch (error) {
      console.error('Error creating floor plan:', error);
      return null;
    }
  }

  async deleteFloorPlan(id: string): Promise<boolean> {
    try {
      // Rimuovi i tavoli associati
      await this.supabaseService.getSupabaseClient()
        .from('tables')
        .update({ floor_plan_id: null })
        .eq('floor_plan_id', id);

      // Elimina la mappa
      const { error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .delete()
        .eq('id', id);

      if (error) throw error;

      await this.loadData();
      return true;
    } catch (error) {
      console.error('Error deleting floor plan:', error);
      return false;
    }
  }

  // Metodo per ottenere le dimensioni predefinite basate sul device
  getDefaultDimensions(): { width: number; height: number } {
    const isMobile = window.innerWidth < 768;
    return {
      width: isMobile ? 800 : 1000,
      height: isMobile ? 600 : 800
    };
  }

  getMergedTableName(selectedTables: Table[]): string {
    const numbers = selectedTables.map(t => t.table_number).join('-');
    return `Tavolo Unito ${numbers}`;
  }

  getMergedTableNumber(selectedTables: Table[]): string {
    return `U${selectedTables.map(t => t.table_number).join('')}`;
  }

  getTotalCapacity(selectedTables: Table[]): number {
    return selectedTables.reduce((sum, t) => sum + t.capacity, 0);
  }

  getPreviewBorderRadius(shape: string, borderRadius: number): string {
    return shape === 'circle' ? '50%' : borderRadius + 'px';
  }

  getPreviewBorderRadiusValue(shape: string, borderRadius: number): string {
    return shape === 'circle' ? '50% (automatico)' : borderRadius + 'px';
  }

  getSelectedTableNumbers(selectedTables: Table[]): string {
  return selectedTables.map(t => t.table_number).join('-');
}

// Aggiungi un metodo per aggiornare la versione corrente
async setCurrentVersion(floorPlanId: string, version: number): Promise<boolean> {
  try {
    const { error } = await this.supabaseService.getSupabaseClient()
      .from('restaurant_floor_plans')
      .update({ current_version: version, updated_at: new Date().toISOString() })
      .eq('id', floorPlanId);
    if (error) throw error;
    return true;
  } catch (error) {
    console.error('❌ Error setting current version:', error);
    return false;
  }
}

}